"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[8624],{50:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/MariOT_Matrix/docs/abuse_of_trusted_relationships","label":"Abuse of Trusted Relationships","docId":"abuse_of_trusted_relationships","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/drive_by_compromise","label":"Drive-by Compromise","docId":"drive_by_compromise","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/infiltration_through_removable_media","label":"Infiltration Through Removable Media","docId":"infiltration_through_removable_media","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/network_denial_of_service","label":"Network Denial of View","docId":"network_denial_of_service","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/site_infiltration","label":"Site Infiltration","docId":"site_infiltration","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/spearphishing_attachment","label":"Spearphishing Attachment","docId":"spearphishing_attachment","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/supply_chain_compromise","label":"Supply Chain Compromise","docId":"supply_chain_compromise","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/wireless_compromise","label":"Wireless Compromise","docId":"wireless_compromise","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/module_firmware","label":"Module Firmware","docId":"module_firmware","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/user_execution","label":"User Execution","docId":"user_execution","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/system_firmware","label":"System Firmware","docId":"system_firmware","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/exploitation_for_privilege_escalation","label":"Exploitation for Privilege Escalation","docId":"exploitation_for_privilege_escalation","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/spoof_reporting_message","label":"Spoof Reporting Message","docId":"spoof_reporting_message","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/network_connection_enumeration","label":"Network Connection Enumeration","docId":"network_connection_enumeration","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/network_sniffing","label":"Network Sniffing","docId":"network_sniffing","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/wireless_sniffing","label":"Wireless Sniffing","docId":"wireless_sniffing","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/default_credentials","label":"Default Credentials","docId":"default_credentials","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/exploitation_of_remote_services","label":"Exploitation of Remote Services","docId":"exploitation_of_remote_services","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/program_download","label":"Program Download","docId":"program_download","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/remote_services","label":"Remote Services","docId":"remote_services","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/adversary_in_the_middle","label":"Adversary in the middle","docId":"adversary_in_the_middle","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/valid_accounts","label":"Valid Accounts","docId":"valid_accounts","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/automated_collection","label":"Automated Collection","docId":"automated_collection","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/data_from_local_system","label":"Data from Local System","docId":"data_from_local_system","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/io_image","label":"I/O Image","docId":"io_image","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/monitor_process_state","label":"Monitor Process State","docId":"monitor_process_state","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/point_&_tag_identification","label":"Point & Tag Identification","docId":"point_&_tag_identification","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/program_upload","label":"Program Upload","docId":"program_upload","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/screen_capture","label":"Screen Capture","docId":"screen_capture","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/standard_application_layer_protocol","label":"Standard Application Layer Protocol","docId":"standard_application_layer_protocol","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/alarm_suppression","label":"Alarm Suppression","docId":"alarm_suppression","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/block_command_message","label":"Block Command Message","docId":"block_command_message","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/block_reporting_message","label":"Block Reporting Message","docId":"block_reporting_message","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/change_credential","label":"Change Credential","docId":"change_credential","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/data_destruction","label":"Data Destruction","docId":"data_destruction","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/denial_of_service","label":"Denial of Service","docId":"denial_of_service","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/device_restart_shutdown","label":"Device Restart/Shutdown","docId":"device_restart_shutdown","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/manipulate_io_image","label":"Manipulate I/O Image","docId":"manipulate_io_image","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/modify_alarm_settings","label":"Modify Alarm Settings","docId":"modify_alarm_settings","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/service_stop","label":"Service Stop","docId":"service_stop","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/brute_force_io","label":"Brute Force I/O","docId":"brute_force_io","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/modify_parameter","label":"Modify Parameter","docId":"modify_parameter","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/unauthorized_command_message","label":"Unauthorized Command Message","docId":"unauthorized_command_message","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/damage_to_property","label":"Damage to Property","docId":"damage_to_property","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/denial_of_control","label":"Denial of Control","docId":"denial_of_control","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/denial_of_view","label":"Denial of View","docId":"denial_of_view","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/loss_of_availability","label":"Loss of Availability","docId":"loss_of_availability","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/loss_of_control","label":"Loss of Control","docId":"loss_of_control","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/loss_of_productivity_and_revenue","label":"Loss of Productivity and Revenue","docId":"loss_of_productivity_and_revenue","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/loss_of_protection","label":"Loss of Protection","docId":"loss_of_protection","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/loss_of_safety","label":"Loss of Safety","docId":"loss_of_safety","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/loss_of_view","label":"Loss of View","docId":"loss_of_view","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/manipulation_of_control","label":"Manipulation of Control","docId":"manipulation_of_control","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/manipulation_of_view","label":"Manipulation of View","docId":"manipulation_of_view","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/signal_manipulation","label":"Signal Manipulation for Radar Systems","docId":"signal_manipulation","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/automatic_identification_system","label":"AIS Exploitation","docId":"automatic_identification_system","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/global_positioning_system","label":"GPS Spoofing","docId":"global_positioning_system","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/false_data_injection","label":"False Data Injection","docId":"false_data_injection","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/replay_attack","label":"Replay Attack","docId":"replay_attack","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/sensact_manipulation","label":"Sensor & Actuator Manipulation","docId":"sensact_manipulation","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/generation_system_attack","label":"Generation System Attack","docId":"generation_system_attack","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/distribution_system_attack","label":"Distribution System Attack","docId":"distribution_system_attack","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/ais_spoofing","label":"AIS Spoofing","docId":"ais_spoofing","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/automated_task_execution","label":"Automated Task Execution","docId":"automated_task_execution","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/command_and_scripting_interpreter","label":"Command and Scripting Interpreter","docId":"command_and_scripting_interpreter","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/configuration_hijacking","label":"Configuration Hijacking","docId":"configuration_hijacking","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/execution_via_gui","label":"Execution via GUI","docId":"execution_via_gui","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/hardcoded_or_default_credentials","label":"Hardcoded or Default Credentials","docId":"hardcoded_or_default_credentials","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/modify_control_logic","label":"Modify Control Logic","docId":"modify_control_logic","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/native_api_execution","label":"Native API Execution","docId":"native_api_execution","unlisted":false},{"type":"link","href":"/MariOT_Matrix/docs/remote_maintenance_exploitation","label":"Remote Maintenance Exploitation","docId":"remote_maintenance_exploitation","unlisted":false}]},"docs":{"abuse_of_trusted_relationships":{"id":"abuse_of_trusted_relationships","title":"Abuse of Trusted Relationships","description":"Abuse of Trusted Relationships in maritime OT environments refers to scenarios where attackers manipulate or impersonate third parties trusted by vessel systems\u2014such as shore-based IT support staff, remote diagnostics providers, maintenance technicians, equipment vendors, or system integrators\u2014to gain unauthorized access, perform malicious actions, or further infiltrate shipboard control networks. These attacks often exploit existing remote access privileges or leverage social engineering tactics to impersonate trusted entities and bypass perimeter defenses.(https//support.microsoft.com/en-us/topic/partners-offer-delegated-administration-26530dc0-ebba-415b-86b1-b55bc06b073e?ui=en-us&rs=en-us&ad=us)","sidebar":"tutorialSidebar"},"adversary_in_the_middle":{"id":"adversary_in_the_middle","title":"Adversary in the middle","description":"Adversaries may modify maritime network traffic in real time using adversary-in-the-middle (AiTM) attacks. These attacks allow adversaries to intercept, block, log, modify, or inject traffic between maritime devices. Common methods include Address Resolution Protocol (ARP) poisoning and the use of proxies.","sidebar":"tutorialSidebar"},"ais_spoofing":{"id":"ais_spoofing","title":"AIS Spoofing","description":"Automatic Identification System (AIS) spoofing involves broadcasting false vessel data (identity, location, course, etc.) to mislead tracking systems. In maritime contexts, attackers or illicit actors can create \u201cghost ships\u201d \u2013 phantom vessels that appear on AIS monitors but do not exist \u2013 or hide the real movements of a ship. This deception can trick port authorities and other ships, mask illegal activities (like sanctions evasion or smuggling), and cause confusion in navigation.\u200b(https~:text=The%20ships%20were%20digital%20fabrications%2C,AIS%20systems%20to%20cyber%20manipulation)","sidebar":"tutorialSidebar"},"alarm_suppression":{"id":"alarm_suppression","title":"Alarm Suppression","description":"Adversaries may target protection function alarms to prevent them from notifying operators of critical conditions in maritime environments. Alarm messages are often part of an overall reporting system, making them particularly interesting to adversaries. However, disrupting the alarm system does not necessarily imply disrupting the reporting system as a whole.","sidebar":"tutorialSidebar"},"automated_collection":{"id":"automated_collection","title":"Automated Collection","description":"Adversaries may automate collection of maritime environment information using tools or scripts. This automated collection may leverage native maritime control protocols and tools available in the maritime systems environment. For example, the NMEA protocol may be used to enumerate and gather information. Access to a system or interface with these native protocols may allow collection and enumeration of other attached, communicating servers and devices.","sidebar":"tutorialSidebar"},"automated_task_execution":{"id":"automated_task_execution","title":"Automated Task Execution","description":"Automated Task Execution in maritime operational technology (OT) environments refers to adversaries leveraging PLC cyclic tasks, HMI automation routines, vessel automation scripts, or remote maintenance scheduling to maintain persistence within shipboard and port control systems. Attackers exploit these mechanisms to execute unauthorized commands on navigation control units, cargo management systems, power distribution networks, and propulsion control systems, allowing continuous and covert access to critical maritime OT infrastructure.(https://www.ics-shipping.org/wp-content/uploads/2020/08/guidelines-on-cyber-security-onboard-ships-min.pdf)","sidebar":"tutorialSidebar"},"automatic_identification_system":{"id":"automatic_identification_system","title":"Automatic Identification System(AIS) Exploitation","description":"Adversaries may exploit the Automatic Identification System (AIS), a self-reporting system mandated by the International Maritime Organization in 2004 for enhancing situational awareness of maritime vessels. The AIS, which uses the VHF radio link, is fundamentally vulnerable to cyberattacks due to its lack of authentication or encryption.","sidebar":"tutorialSidebar"},"block_command_message":{"id":"block_command_message","title":"Block Command Message","description":"Adversaries may block a command message from reaching its intended target to prevent command execution in maritime environments. In maritime OT networks, command messages are sent to provide instructions to control system devices. A blocked command message can inhibit response functions from correcting a disruption or addressing an unsafe condition.","sidebar":"tutorialSidebar"},"block_reporting_message":{"id":"block_reporting_message","title":"Block Reporting Message","description":"Adversaries may block or prevent a reporting message from reaching its intended target in maritime environments. In maritime control systems, reporting messages contain telemetry data (e.g., I/O values) pertaining to the current state of equipment and the vessel\'s operations. By blocking these reporting messages, an adversary can potentially hide their actions from an operator.","sidebar":"tutorialSidebar"},"brute_force_io":{"id":"brute_force_io","title":"Brute Force I/O","description":"Adversaries may stop or disable services on a maritime system to render those services unavailable to legitimate users. Stopping critical services can inhibit or stop response to an incident or aid in the adversary\'s overall objectives to cause damage to the vessel\'s operations. Services may not allow for modification of their data stores while running. Adversaries may stop services in order to conduct Data Destruction.","sidebar":"tutorialSidebar"},"change_credential":{"id":"change_credential","title":"Change Credential","description":"Adversaries may block or prevent a reporting message from reaching its intended target in maritime environments. In maritime control systems, reporting messages contain telemetry data (e.g., I/O values) pertaining to the current state of equipment and the vessel\'s operations. By blocking these reporting messages, an adversary can potentially hide their actions from an operator.","sidebar":"tutorialSidebar"},"command_and_scripting_interpreter":{"id":"command_and_scripting_interpreter","title":"Command and Scripting Interpreter","description":"In the maritime cybersecurity framework, Command and Scripting Interpreter refers to the use of command-line interfaces (CLI), scripting languages, or built-in interpreters to execute commands on onboard or offshore systems.(https//sec.cloudapps.cisco.com/security/center/resources/integrity_assurance.html#23)(https://thepythoncode.com/article/executing-bash-commands-remotely-in-python)","sidebar":"tutorialSidebar"},"configuration_hijacking":{"id":"configuration_hijacking","title":"Configuration Hijacking","description":"An adversarial technique in which the attacker modifies application-level configuration files to reroute inputs, alter system behavior, or masquerade as legitimate components. In maritime OT systems, this may involve changing data source paths in navigation software (e.g., OpenCPN) to redirect serial input to adversary-controlled interfaces, achieving persistent control without escalating privileges. The behavior aligns with persistence goals and enables covert interception or injection of operational data streams.","sidebar":"tutorialSidebar"},"damage_to_property":{"id":"damage_to_property","title":"Damage to Property","description":"Adversaries may cause damage and destruction of property to maritime infrastructure, vessels, and the surrounding marine environment when attacking control systems. This technique may result in equipment failure or operational breakdown, or represent collateral damage from other techniques used in an attack. Depending on the severity of physical damage and disruption caused to control processes and systems, this technique may result in Loss of Safety. Operations that result in Loss of Control may also cause damage to property, which may be directly or indirectly motivated by an adversary seeking to cause impact in the form of Loss of Productivity and Revenue.","sidebar":"tutorialSidebar"},"data_destruction":{"id":"data_destruction","title":"Data Destruction","description":"Adversaries may perform data destruction over the course of an operation in maritime environments. They may drop or create malware, tools, or other non-native files on a target system to accomplish this, potentially leaving behind traces of malicious activities. Such non-native files and other data may be removed over the course of an intrusion to maintain a small footprint or as a standard part of the post-intrusion cleanup process.","sidebar":"tutorialSidebar"},"data_from_local_system":{"id":"data_from_local_system","title":"Data from Local System","description":"Adversaries may target and collect data from maritime system sources, such as vessel file systems, configuration files, or onboard databases. This can include sensitive data such as ship specifications, navigation schematics, or diagrams of control system layouts, maritime devices, and operational processes.","sidebar":"tutorialSidebar"},"default_credentials":{"id":"default_credentials","title":"Default Credentials","description":"Adversaries may seek to capture radio frequency (RF) communication used for remote control and reporting in maritime environments. RF communication frequencies vary between 3 kHz to 300 GHz, although are commonly between 300 MHz to 6 GHz. The wavelength and frequency of the signal affect how the signal propagates through open air, obstacles (e.g., ship structures and cargo), and the type of radio required to capture them. These characteristics are often standardized in the protocol and hardware and may affect how the signal is captured. Some examples of wireless protocols that may be found in maritime environments are: WirelessHART, Zigbee, WIA-FA, and 700 MHz Public Safety Spectrum.","sidebar":"tutorialSidebar"},"denial_of_control":{"id":"denial_of_control","title":"Denial of Control","description":"Adversaries may cause a denial of control to temporarily prevent maritime operators and engineers from interacting with process controls. An adversary may attempt to deny process control access to cause a temporary loss of communication with the control device or to prevent operator adjustment of maritime process controls. An affected process may still be operating during the period of control loss, but not necessarily in a desired state.","sidebar":"tutorialSidebar"},"denial_of_service":{"id":"denial_of_service","title":"Denial of Service","description":"Adversaries may perform Denial-of-Service (DoS) attacks to disrupt expected vessel functionality. Examples of DoS attacks include overwhelming the target maritime system with a high volume of requests in a short time period and sending the target system a request it does not know how to handle. Disrupting system state may temporarily render it unresponsive, possibly lasting until a reboot can occur. When placed in this state, maritime systems may be unable to send and receive requests, and may not perform expected response functions in reaction to other events in the environment.","sidebar":"tutorialSidebar"},"denial_of_view":{"id":"denial_of_view","title":"Denial of View","description":"Adversaries may cause a denial of view to disrupt and prevent operator oversight of a maritime vessel\'s status. This can involve leveraging Denial-of-Service (DoS) attacks to overwhelm onboard systems with data requests, rendering them inoperable and disrupting essential communication channels. This tactic can hinder the crew\'s ability to send and receive critical messages, jeopardizing their response to emergencies and compromising safe navigation.","sidebar":"tutorialSidebar"},"device_restart_shutdown":{"id":"device_restart_shutdown","title":"Device Restart/Shutdown","description":"Adversaries may forcibly restart or shut down a system in a maritime environment to disrupt and potentially negatively impact vessel operations. Methods of system restart and shutdown exist in some maritime systems as built-in, standard functionalities. These functionalities can be executed using interactive system web interfaces, CLIs, and network protocol commands.","sidebar":"tutorialSidebar"},"distribution_system_attack":{"id":"distribution_system_attack","title":"Distribution System Attack","description":"Adversaries may target maritime distribution systems by exploiting vulnerabilities in communication and control networks. This could involve attacking systems that manage power distribution on ships or ports, leading to potential network blockades or power outages. Such attacks may include false data injection, denial of service and replay attacks.","sidebar":"tutorialSidebar"},"drive_by_compromise":{"id":"drive_by_compromise","title":"Drive-by Compromise","description":"Adversaries may gain access to a maritime system during a drive-by compromise, when a crew member or port official visits a website as part of a regular browsing session. With this technique, the user\'s web browser is targeted and exploited simply by visiting the compromised website.","sidebar":"tutorialSidebar"},"execution_via_gui":{"id":"execution_via_gui","title":"Execution via GUI","description":"Execution via GUI (Graphical User Interface) in maritime operational technology (OT) systems refers to adversaries leveraging legitimate OT HMI (Human-Machine Interface), SCADA control panels, or onboard vessel management interfaces to execute unauthorized commands, alter system settings, or deploy malicious scripts.(https//pmc.ncbi.nlm.nih.gov/articles/PMC8124306/)","sidebar":"tutorialSidebar"},"exploitation_for_privilege_escalation":{"id":"exploitation_for_privilege_escalation","title":"Exploitation for Privilege Escalation","description":"Adversaries may exploit software vulnerabilities in maritime systems in an attempt to elevate privileges. Exploitation of a software vulnerability occurs when an adversary takes advantage of a programming error in a maritime control program, service, or within the ship\'s operating system software or kernel itself to execute adversary-controlled code. Security constructs such as permission levels will often hinder access to information and use of certain techniques, so adversaries will likely need to perform privilege escalation to include use of software exploitation to circumvent those restrictions.","sidebar":"tutorialSidebar"},"exploitation_of_remote_services":{"id":"exploitation_of_remote_services","title":"Exploitation of Remote Services","description":"---","sidebar":"tutorialSidebar"},"false_data_injection":{"id":"false_data_injection","title":"False Data Injection","description":"Adversary may execute a False Data Injection (FDI) attack, compromising the integrity of a system by introducing incorrect data. The intention is to mislead or disrupt the system\u2019s standard operations. By manipulating system behaviors and misleading users, the adversary can weaken security measures, leading to erroneous decisions and malfunctions. For example, in a smart grid, an FDI attack could disrupt power distribution.","sidebar":"tutorialSidebar"},"generation_system_attack":{"id":"generation_system_attack","title":"Generation System Attack","description":"Adversaries may manipulate maritime power systems, including generating stations, through control devices that manage these systems. They can manipulate data in these controllers by opening and closing the circuit breaker of the generator, causing instability and desynchronization in the power generation process. This can hamper the stability of the maritime power system. Additionally, adversaries may mislead frequency controllers to perform fake frequency determinations for load shedding, resulting in significant losses and delays in power generation.","sidebar":"tutorialSidebar"},"global_positioning_system":{"id":"global_positioning_system","title":"Global Positioning System(GPS) Spoofing","description":"Adversaries may exploit GPS systems by spoofing coordinates, causing significant disruptions in maritime operations. This can mislead navigation systems like the Electronic Chart Display and Information System (ECDIS) to display inaccurate positions. By injecting false GPS data through Ethernet-based networks using the IEC 61162-450 standard, adversaries can execute the Maritime GPS Spoofing Injection (M-GPSI) technique. This manipulation compromises the safety and efficiency of maritime operations, potentially leading to navigational errors, collisions, or groundings.","sidebar":"tutorialSidebar"},"hardcoded_or_default_credentials":{"id":"hardcoded_or_default_credentials","title":"Hardcoded or Default Credentials","description":"Hardcoded or Default Credentials refer to pre-configured administrative usernames and passwords that are embedded in maritime equipment OT during manufacturing. These credentials are often not changed or removed after the deployment, creating a persistent configuration weakness. If an attacker obtains low-privilege access to the system, the presence of default or hardcoded accounts can enable privilege escalation to administrative levels. Many shipboard control systems, including navigation platforms such as ECDIS and programmable controllers such as PLC, come with factory-default passwords or undocumented maintenance accounts. Without proper reconfiguration during installation or commissioning, these default credentials may remain active in operational environments. Attackers can exploit this oversight by logging into the system using known credentials to gain administrator-level control. This issue is considered a configuration flaw rather than a software vulnerability. However, it represents a notable security risk as it provides a direct path from user-level access to full system control.","sidebar":"tutorialSidebar"},"infiltration_through_removable_media":{"id":"infiltration_through_removable_media","title":"Infiltration Through Removable Media","description":"Adversaries may use USB drives or other removable storage devices to introduce malware into onboard systems. This technique leverages the physical connection of infected media to vessel networks, bypassing traditional cybersecurity measures. The threat is particularly critical in maritime operations, where compromised systems can disrupt navigation, communication, and operational technology (OT) essential for safe and efficient maritime operations. Regular training, strict media usage policies, and advanced threat detection solutions are crucial for mitigating these risks.","sidebar":"tutorialSidebar"},"io_image":{"id":"io_image","title":"I/O Image","description":"Adversaries may seek to capture process values related to the inputs and outputs of a ship\'s PLC. During the scan cycle, a PLC on a vessel reads the status of all inputs and stores them in an image table. The image table is the PLC\'s internal storage location where values of inputs/outputs for one scan are stored while it executes the user program. After the PLC has solved the entire logic program, it updates the output image table. The contents of this output image table are written to the corresponding output points in I/O Modules.","sidebar":"tutorialSidebar"},"loss_of_availability":{"id":"loss_of_availability","title":"Loss of Availability","description":"Adversaries may attempt to disrupt essential maritime components or systems to prevent ship owners and operators from delivering cargo or services.","sidebar":"tutorialSidebar"},"loss_of_control":{"id":"loss_of_control","title":"Loss of Control","description":"Adversaries may seek to achieve a sustained loss of control or a runaway condition in which maritime operators cannot issue any commands even if the malicious interference has subsided. This could result in significant disruptions to shipping traffic, cargo handling, and overall port operations, leading to unsafe conditions and potential economic losses.","sidebar":"tutorialSidebar"},"loss_of_productivity_and_revenue":{"id":"loss_of_productivity_and_revenue","title":"Loss of Productivity and Revenue","description":"Adversaries may cause loss of productivity and revenue in maritime operations by disrupting and damaging control system operations, devices, and processes. This can occur directly through ICS-targeting attacks or indirectly through IT-targeting attacks in non-segregated environments. When port operations or maritime services are halted, it impacts the entire supply chain, causing shortages and increased prices. For instance, a ransomware attack on a major shipping company could halt cargo handling, leading to potential shortages and delays in goods delivery. Similarly, a cyberattack on port operations could significantly disrupt fuel transportation, akin to the 2021 Colonial Pipeline incident.","sidebar":"tutorialSidebar"},"loss_of_protection":{"id":"loss_of_protection","title":"Loss of Protection","description":"Adversaries may compromise maritime protective systems designed to prevent the effects of faults and abnormal conditions, resulting in equipment damage, prolonged disruptions, and hazards to personnel. Maritime operations often encounter rapid faults where human reaction is insufficient, making automated protection crucial. Adversaries may target and disable these systems to enable subsequent attacks or allow faults to go unchecked. Detection of compromised protection can lead to process shutdowns, causing significant productivity and revenue losses, aligning with adversaries\' goals to disrupt maritime processes.","sidebar":"tutorialSidebar"},"loss_of_safety":{"id":"loss_of_safety","title":"Loss of Safety","description":"Adversaries may compromise maritime safety system functions designed to maintain safe operations during dangerous conditions. These systems, similar to control systems, ensure processes fail safely. Rapid unsafe conditions often exceed human reaction times, making automated safety responses critical. Adversaries may disable these functions to enable further attacks or allow unsafe conditions to persist. Detecting such compromises can lead to process shutdowns due to strict safety policies, causing significant productivity and revenue losses, aligning with adversaries\' goals to disrupt maritime operations.","sidebar":"tutorialSidebar"},"loss_of_view":{"id":"loss_of_view","title":"Loss of View","description":"Adversaries may cause a sustained or permanent loss of view in maritime systems, requiring local, hands-on operator intervention such as a restart or manual operation. By disrupting reporting or visibility, adversaries can effectively hide the current state of maritime operations without affecting the physical processes themselves. This can prevent operators from detecting issues in real-time, increasing the risk of undetected faults and potential safety hazards.","sidebar":"tutorialSidebar"},"manipulate_io_image":{"id":"manipulate_io_image","title":"Manipulate I/O Image","description":"Adversaries may manipulate the I/O image of maritime control systems through various means to prevent them from functioning as expected. Methods of I/O image manipulation may include overriding the I/O table via direct memory manipulation or using the override function used for testing control system programs. During the scan cycle, a maritime control system reads the status of all inputs and stores them in an image table. The image table is the system\'s internal storage location where values of inputs/outputs for one scan are stored while it executes the user program. After the system has solved the entire logic program, it updates the output image table. The contents of this output image table are written to the corresponding output points in I/O Modules.","sidebar":"tutorialSidebar"},"manipulation_of_control":{"id":"manipulation_of_control","title":"Manipulation of Control","description":"Adversaries may manipulate physical process control within maritime environments. Methods can include changing setpoint values, tags, or other parameters. Adversaries may manipulate control system devices or use their own to command physical processes, either temporarily or for extended periods depending on detection. Techniques include:","sidebar":"tutorialSidebar"},"manipulation_of_view":{"id":"manipulation_of_view","title":"Manipulation of View","description":"Adversaries may attempt to manipulate information reported to maritime operators or controllers. This manipulation, whether short-term or sustained, can cause operators to believe the system is in a different state than it actually is. As a result, operators might issue harmful commands, introducing faults or catastrophic failures. Inaccurate data can also mislead business analysis systems, leading to poor management decisions. For example, manipulated data might cause inappropriate navigational adjustments, potentially resulting in collisions or grounding of vessels.","sidebar":"tutorialSidebar"},"modify_alarm_settings":{"id":"modify_alarm_settings","title":"Modify Alarm Settings","description":"Adversaries may modify alarm settings to prevent alerts that may inform vessel operators of their presence or to prevent responses to dangerous and unintended scenarios. Reporting messages are a standard part of data acquisition in maritime control systems. Reporting messages are used as a way to transmit system state information and acknowledgements that specific actions have occurred. These messages provide vital information for the management of a vessel\'s operations, and keep operators, engineers, and administrators aware of the state of system devices and physical processes.","sidebar":"tutorialSidebar"},"modify_control_logic":{"id":"modify_control_logic","title":"Modify Control Logic","description":"The Modify Control Logic technique involves adversaries altering the logic or operational parameters of shipboard or port-based control systems. This attack targets Programmable Logic Controllers (PLCs), Supervisory Control and Data Acquisition (SCADA) systems, or other Industrial Control Systems (ICS) used in maritime operations. By modifying control logic, attackers can manipulate system behavior, disrupt normal operations, or cause safety-critical failures in ship propulsion, navigation, or cargo handling systems.","sidebar":"tutorialSidebar"},"modify_parameter":{"id":"modify_parameter","title":"Modify Parameter","description":"Adversaries may modify parameters used to instruct maritime control system devices. These devices operate via programs that dictate how and when to perform actions based on such parameters. These parameters can determine the extent to which an action is performed and may specify additional options. For example, a program on a control system device dictating engine processes may take a parameter defining the total number of seconds to run that engine.","sidebar":"tutorialSidebar"},"module_firmware":{"id":"module_firmware","title":"Module Firmware","description":"Adversaries may install malicious or vulnerable firmware onto modular hardware devices within maritime systems. Control system devices on ships and offshore platforms often contain modular hardware components, each with its own firmware separate from the main control system equipment.","sidebar":"tutorialSidebar"},"monitor_process_state":{"id":"monitor_process_state","title":"Monitor Process State","description":"Adversaries may gather information about the physical process state on a vessel. This information may be used to gain more insight into the maritime process itself or as a trigger for malicious actions. The sources of process state information may vary, such as OPC tags, historian data, specific PLC block information, or network traffic.","sidebar":"tutorialSidebar"},"native_api_execution":{"id":"native_api_execution","title":"Native API Execution","description":"In the maritime sector, Native API Execution poses a significant cybersecurity threat, particularly within shipboard operational technology (OT) environments. (https//dotnet.microsoft.com/zh-cn/learn/dotnet/what-is-dotnet-framework)(https://developer.apple.com/library/archive/documentation/MacOSX/Conceptual/OSXTechnologyOverview/CocoaApplicationLayer/CocoaApplicationLayer.html#//apple_ref/doc/uid/TP40001067-CH274-SW1)","sidebar":"tutorialSidebar"},"network_connection_enumeration":{"id":"network_connection_enumeration","title":"Network Connection Enumeration","description":"Adversaries may perform network connection enumeration to discover information about maritime device communication patterns. If an adversary can inspect the state of a network connection with tools, such as Netstat, in conjunction with system firmware, they can determine the role of certain devices on the maritime network. The adversary can also use network sniffing to watch maritime network traffic for details about the source, destination, protocol, and content.","sidebar":"tutorialSidebar"},"network_denial_of_service":{"id":"network_denial_of_service","title":"Network Denial of View","description":"Adversaries may cause a denial of view to disrupt and prevent operator oversight on the status of a maritime environment. This may manifest as a temporary communication failure between a device and its control source, with the interface recovering and becoming available once the interference ceases.","sidebar":"tutorialSidebar"},"network_sniffing":{"id":"network_sniffing","title":"Network Sniffing","description":"Network sniffing is the practice of using a network interface on a maritime system to monitor or capture information regardless of whether it is the specified destination for the information.","sidebar":"tutorialSidebar"},"point_&_tag_identification":{"id":"point_&_tag_identification","title":"Point & Tag Identification","description":"Adversaries may collect point and tag values to gain a more comprehensive understanding of the maritime process environment. Points may be values such as inputs, memory locations, outputs, or other process-specific variables. Tags are the identifiers given to points for operator convenience.","sidebar":"tutorialSidebar"},"program_download":{"id":"program_download","title":"Program Download","description":"Adversaries may perform a program download to transfer a user program to a maritime control system controller.","sidebar":"tutorialSidebar"},"program_upload":{"id":"program_upload","title":"Program Upload","description":"Adversaries may attempt to upload a program from a ship\'s PLC to gather information about a maritime process. Uploading a program may allow them to acquire and study the underlying logic. Methods of program upload include vendor software, which enables the user to upload and read a program running on a PLC. This software can be used to upload the target program to a workstation, jump box, or an interfacing device on the vessel.","sidebar":"tutorialSidebar"},"remote_maintenance_exploitation":{"id":"remote_maintenance_exploitation","title":"Remote Maintenance Exploitation","description":"In the maritime sector, Remote Maintenance Exploitation (RME) refers to cyber adversaries leveraging vulnerabilities in remote maintenance and support systems to gain unauthorized access and control over critical maritime infrastructure.(https://support.apple.com/zh-cn/guide/remote-desktop/apdbed09830/mac) Remote maintenance is commonly used for monitoring, troubleshooting, and optimizing shipboard automation, propulsion, fuel management, navigation, and surveillance systems. However, if access controls are weak, authentication mechanisms are flawed, or software vulnerabilities exist, attackers can exploit these entry points to infiltrate maritime networks, execute malicious actions, or disrupt vessel operations.","sidebar":"tutorialSidebar"},"remote_services":{"id":"remote_services","title":"Remote Services","description":"Adversaries may leverage remote services to move between maritime assets and network segments. These services are often used to allow operators to interact with systems remotely within the network; some examples are RDP, SMB, SSH, and other similar mechanisms.","sidebar":"tutorialSidebar"},"replay_attack":{"id":"replay_attack","title":"Replay Attack","description":"Adversaries may perform a replay attack to exploit the communication protocols within maritime systems. In a replay attack, an adversary captures valid data transmissions and retransmits them to create unauthorized effects. This type of attack can disrupt operations, cause navigational errors, or lead to unauthorized control of systems. By replaying previously captured data, adversaries can mislead shipboard systems into executing commands based on outdated or falsified information.","sidebar":"tutorialSidebar"},"screen_capture":{"id":"screen_capture","title":"Screen Capture","description":"Adversaries may attempt to perform screen capture of devices in the maritime control system environment. Screenshots may be taken of workstations, HMIs, or other devices that display environment-relevant process, device, reporting, alarm, or related data. These device displays may reveal information regarding the maritime process, layout, control, and related schematics. In particular, an HMI can provide a lot of important maritime process information. Analysis of screen captures may provide the adversary with an understanding of intended operations and interactions between critical devices on the vessel.","sidebar":"tutorialSidebar"},"sensact_manipulation":{"id":"sensact_manipulation","title":"Sensor & Actuator Manipulation","description":"Adversaries may exploit sensor and actuator systems in Operational Technology (OT) environments to disrupt critical operations, compromise safety measures, and influence decision-making. This could be achieved through various methods such as tampering with sensor readings, manipulating actuator commands, or even creating phantom operations in the system. Such manipulations can cause operational anomalies, misdirect resources, or lead to incorrect strategic decisions. The impact of these actions can be significant, given the pivotal role of sensors and actuators in maintaining the efficiency, safety, and reliability of OT systems.","sidebar":"tutorialSidebar"},"service_stop":{"id":"service_stop","title":"Service Stop","description":"Adversaries may stop or disable services on a maritime system to render those services unavailable to legitimate users. Stopping critical services can inhibit or stop response to an incident or aid in the adversary\'s overall objectives to cause damage to the vessel\'s operations. Services may not allow for modification of their data stores while running. Adversaries may stop services in order to conduct Data Destruction.","sidebar":"tutorialSidebar"},"signal_manipulation":{"id":"signal_manipulation","title":"Signal Manipulation for Radar Systems","description":"Adversaries may manipulate radar data or the radar system itself to disrupt critical operations, impede situational awareness, and influence decision-making. This could be achieved through various methods such as injecting false targets, altering the perceived location of vessels, or even creating phantom vessels on the radar screen. Such manipulations can cause confusion, misdirect resources, or lead to incorrect tactical decisions.","sidebar":"tutorialSidebar"},"site_infiltration":{"id":"site_infiltration","title":"Site Infiltration","description":"Adversaries may physically infiltrate maritime premises to install malicious devices or software on shipboard or port computers. This is not confined to the installation of devices such as key-loggers but also includes tactics to entice crew members or port employees into installing these malicious entities on their work computers. The attack methods can range from software exploits to hardware tampering, depending on the resources and objectives of the attacker.","sidebar":"tutorialSidebar"},"spearphishing_attachment":{"id":"spearphishing_attachment","title":"Spearphishing Attachment","description":"Adversaries may use a spearphishing attachment, a variant of spearphishing, as a form of social engineering attack against specific maritime targets. Spearphishing attachments are different from other forms of spearphishing in that they employ malware attached to an email. All forms of spearphishing are electronically delivered and target a specific individual, company, or industry. In this scenario, adversaries attach a file to the spearphishing email and usually rely upon User Execution to gain execution and access.","sidebar":"tutorialSidebar"},"spoof_reporting_message":{"id":"spoof_reporting_message","title":"Spoof Reporting Message","description":"Adversaries may spoof reporting messages in maritime control system environments for evasion and to impair process control. In maritime control systems, reporting messages contain telemetry data (e.g., I/O values) pertaining to the current state of ship equipment and maritime processes. Reporting messages are important for monitoring the normal operation of a system or identifying important events such as deviations from expected values.","sidebar":"tutorialSidebar"},"standard_application_layer_protocol":{"id":"standard_application_layer_protocol","title":"Standard Application Layer Protocol","description":"Adversaries may establish command and control capabilities over commonly used maritime application layer protocols such as HTTP(S), OPC, RDP, telnet, DNP3, and modbus. These protocols may be used to disguise adversary actions as benign network traffic. Standard protocols may be seen on their associated port or, in some cases, over a non-standard port. Adversaries may use these protocols to reach out of the vessel\'s network for command and control, or, in some cases, to other infected devices within the maritime network.","sidebar":"tutorialSidebar"},"supply_chain_compromise":{"id":"supply_chain_compromise","title":"Supply Chain Compromise","description":"Adversaries may perform supply chain compromise to gain access to maritime control systems environments by means of infected products, software, and workflows. Supply chain compromise involves the manipulation of products, such as devices or software, or their delivery mechanisms before receipt by the end consumer. Adversary compromise of these products and mechanisms is done with the goal of data or system compromise once infected products are introduced to the target environment.","sidebar":"tutorialSidebar"},"system_firmware":{"id":"system_firmware","title":"System Firmware","description":"System firmware on modern maritime assets is often designed with an update feature. Older device firmware may be factory installed and require special reprogramming equipment. When available, the firmware update feature enables vendors to remotely patch bugs and perform upgrades. Device firmware updates are often delegated to the user and may be done using a software update package. It may also be possible to perform this task over the network.","sidebar":"tutorialSidebar"},"unauthorized_command_message":{"id":"unauthorized_command_message","title":"Unauthorized Command Message","description":"Adversaries may send unauthorized command messages to instruct maritime control system assets to perform actions outside of their intended functionality or without the logical preconditions to trigger their expected function. Command messages are used in maritime control networks to give direct instructions to control system devices. If an adversary can send an unauthorized command message to a maritime control system, they can instruct the device to perform an action outside the normal bounds of its operations. An adversary could potentially instruct a maritime control system device to perform an action that will cause an impact.","sidebar":"tutorialSidebar"},"user_execution":{"id":"user_execution","title":"User Execution","description":"Adversaries may rely on a targeted maritime organization\'s user interaction for the execution of malicious code. User interaction may consist of installing applications, opening email attachments, or granting higher permissions to documents.","sidebar":"tutorialSidebar"},"valid_accounts":{"id":"valid_accounts","title":"Valid Accounts","description":"Adversaries may steal the credentials of a specific crew member or service account using credential access techniques. In some cases, default credentials for maritime control system devices may be publicly available. Compromised credentials may be used to bypass access controls placed on various resources on ships and within the maritime network, and may even be used for persistent access to remote systems. Compromised and default credentials may also grant an adversary increased privilege to specific systems and devices or access to restricted areas of the maritime network. Adversaries may choose not to use malware or tools, in conjunction with the legitimate access those credentials provide, to make it harder to detect their presence or to control devices and send legitimate commands in an unintended way.","sidebar":"tutorialSidebar"},"wireless_compromise":{"id":"wireless_compromise","title":"Wireless Compromise","description":"Adversaries may perform wireless compromise as a method of gaining communications and unauthorized access to a maritime wireless network. Access to a wireless network may be gained through the compromise of a wireless device. Adversaries may also utilize radios and other wireless communication devices on the same frequency as the wireless network. Wireless compromise can be done as an initial access vector from a remote distance.","sidebar":"tutorialSidebar"},"wireless_sniffing":{"id":"wireless_sniffing","title":"Wireless Sniffing","description":"Adversaries may seek to capture radio frequency (RF) communication used for remote control and reporting in maritime environments. RF communication frequencies vary between 3 kHz to 300 GHz, although are commonly between 300 MHz to 6 GHz. The wavelength and frequency of the signal affect how the signal propagates through open air, obstacles (e.g., ship structures and cargo), and the type of radio required to capture them. These characteristics are often standardized in the protocol and hardware and may affect how the signal is captured. Some examples of wireless protocols that may be found in maritime environments are: WirelessHART, Zigbee, WIA-FA, and 700 MHz Public Safety Spectrum.","sidebar":"tutorialSidebar"}}}}')}}]);